#include <bits/stdc++.h>
using namespace std;

int n, m, a[105];

bool cmp(int a, int b) {
    return a > b;
}

int main() {
    cin >> n >> m;
    for (int i = 0; i < n * m; i++) {
        cin >> a[i];
    }
    int tmp = a[0];
    sort(a, a + n * m, cmp);
    for (int i = 0; i < n * m; i++) {
        if (a[i] == tmp) {
            printf("%d %d\n", i / n + 1, (i / n % 2 == 0 ? i % n + 1 : n - i % n));
            return 0;
        }
    }
    return 0;
}

